  "executive_summary": "Anti-Corruption Layer (ACL) per external system, unified internal domain event bus, and dedicated adapter components that translate between the platform's ubiquitous language and each external system's protocol/format. The architecture isolates protocol concerns (SFTP/XML, REST/webhooks, Kafka) behind clean ports, keeps the core domain model unpolluted, and ensures each integration can evolve independently.",

  "architecture": {
    "components": [
      {
        "name": "Order Domain Service",
        "responsibility": "Owns order lifecycle: OrderPlaced → OrderConfirmed. Publishes domain events to the internal event bus. Enforces order invariants (valid items, confirmed inventory, idempotent confirmation).",
        "boundaries": "No knowledge of SAP, DHL, or Kafka. Communicates only through domain events and repository abstractions."
      },
      {
        "name": "Shipment Domain Service",
        "responsibility": "Owns shipment lifecycle: ShipmentCreated → DeliveryAttempted → DeliveryCompleted/DeliveryFailed. Reacts to OrderConfirmed, publishes shipment domain events.",
        "boundaries": "No knowledge of external carrier APIs. Receives delivery status updates through a port interface, not directly from webhooks."
      },
      {
        "name": "Internal Event Bus",
        "responsibility": "In-process or lightweight broker (e.g., internal Kafka topic, or in-memory bus with outbox) that distributes domain events to all interested adapters and services. Guarantees at-least-once delivery via transactional outbox pattern.",
        "boundaries": "Carries only canonical domain events in the platform's ubiquitous language. No external system DTOs ever appear on this bus."
      },
      {
        "name": "SAP ERP Adapter (System A ACL)",
        "responsibility": "Polls SFTP endpoint every 15 minutes, retrieves XML files, parses and validates them, translates SAP order confirmations into OrderConfirmed domain events. Handles file deduplication, retry on SFTP failure, and XML schema validation.",
        "boundaries": "Owns all SAP-specific knowledge: XML schema, SFTP credentials, file naming conventions, SAP order ID mapping. Exposes nothing SAP-specific beyond this component."
      },
      {
        "name": "DHL Carrier Adapter (System B ACL)",
        "responsibility": "Two sub-components: (1) Outbound Client — calls DHL REST API to create shipments when ShipmentCreated fires. (2) Inbound Webhook Handler — receives DHL status callbacks, translates them into DeliveryAttempted/DeliveryCompleted/DeliveryFailed events. Must respond to webhooks within 500ms.",
        "boundaries": "Owns all DHL-specific knowledge: API auth, payload schemas, status code mappings, retry/circuit-breaker logic. The webhook handler is a thin HTTP endpoint that enqueues work asynchronously to meet the 500ms SLA."
      },
      {
        "name": "Analytics Stream Adapter (System C ACL)",
        "responsibility": "Subscribes to all domain events on the internal event bus and publishes them to the external Kafka cluster in the analytics platform's required schema. Handles schema translation, serialization (likely Avro/JSON), and Kafka producer reliability (acks, retries, idempotent producer).",
        "boundaries": "Owns the analytics event schema mapping. If the analytics platform changes its schema, only this adapter changes. Core domain is unaffected."
      },
      {
        "name": "Transactional Outbox",
        "responsibility": "Ensures domain events are reliably published even if the broker is temporarily unavailable. Domain services write events to an outbox table in the same DB transaction as state changes. A relay process (polling or CDC) forwards them to the event bus.",
        "boundaries": "Lives at the persistence layer. Guarantees at-least-once delivery semantics. All consumers must be idempotent."
      },
      {
        "name": "Webhook Ingress Gateway",
        "responsibility": "Lightweight HTTP endpoint (separate from main API) that receives DHL webhook callbacks. Validates HMAC signatures, immediately enqueues the raw payload onto an internal queue, and returns 200 OK — all within the 500ms budget. Actual processing happens asynchronously.",
        "boundaries": "Knows only how to authenticate and enqueue. No domain logic. No direct DB writes."
      }
    ],
    "interfaces": [
      {
        "from": "SAP ERP Adapter",
        "to": "Order Domain Service",
        "contract": "Emits OrderConfirmed command/event containing: orderId, confirmedLineItems[], confirmedAt timestamp, sapReferenceId. Adapter calls a domain service method or publishes to a command queue.",
        "coupling_type": "loose — adapter depends on domain interface, not vice versa"
      },
      {
        "from": "Order Domain Service",
        "to": "Internal Event Bus",
        "contract": "Publishes OrderPlaced { orderId, items[], placedAt } and OrderConfirmed { orderId, confirmedAt, externalRef } via transactional outbox.",
        "coupling_type": "event-driven, fully decoupled"
      },
      {
        "from": "Shipment Domain Service",
        "to": "Internal Event Bus",
        "contract": "Publishes ShipmentCreated { shipmentId, orderId, carrier, trackingNumber }, DeliveryAttempted { shipmentId, attemptedAt, location }, DeliveryCompleted { shipmentId, completedAt, signedBy }, DeliveryFailed { shipmentId, failedAt, reason }.",
        "coupling_type": "event-driven, fully decoupled"
      },
      {
        "from": "Internal Event Bus",
        "to": "DHL Carrier Adapter (Outbound)",
        "contract": "Subscribes to ShipmentCreated. Calls DHL REST API POST /shipments with translated payload. Stores DHL tracking ID back via domain service port.",
        "coupling_type": "event-driven subscription, loose coupling"
      },
      {
        "from": "Webhook Ingress Gateway",
        "to": "DHL Carrier Adapter (Inbound)",
        "contract": "Enqueues raw DHL webhook payload { headers, body, receivedAt } onto internal processing queue. Adapter picks up, validates, translates to domain event.",
        "coupling_type": "async queue, fully decoupled from HTTP lifecycle"
      },
      {
        "from": "Internal Event Bus",
        "to": "Analytics Stream Adapter",
        "contract": "Subscribes to ALL domain events. Transforms each into analytics schema and produces to external Kafka topic(s). Contract is the canonical domain event envelope: { eventType, eventId, timestamp, aggregateId, payload }.",
        "coupling_type": "event-driven subscription, loose coupling"
      }
    ],
    "data_flow": "1) Orders originate internally (OrderPlaced) or are confirmed via SAP SFTP XML files (SAP Adapter → OrderConfirmed). 2) OrderConfirmed triggers Shipment Domain Service → ShipmentCreated. 3) ShipmentCreated triggers DHL Adapter outbound call to create carrier shipment. 4) DHL sends webhook callbacks → Webhook Gateway enqueues → DHL Adapter inbound translates to DeliveryAttempted/Completed/Failed → Shipment Domain Service processes and publishes domain events. 5) ALL domain events flow through internal event bus → Analytics Adapter → external Kafka for real-time analytics. The transactional outbox ensures no events are lost between steps.",
    "patterns_used": [
      {
        "pattern": "Anti-Corruption Layer (ACL)",
        "rationale": "Each external system (SAP, DHL, Analytics) has its own data model, protocol, and rate of change. ACLs prevent external model pollution from leaking into the core domain. When SAP changes its XML schema or DHL changes its API version, only the respective adapter changes."
      },
      {
        "pattern": "Transactional Outbox + Event Relay",
        "rationale": "Domain state changes and event publication must be atomic. Writing events to an outbox table in the same transaction as the aggregate state change, then relaying via a separate process, guarantees at-least-once delivery without distributed transactions."
      },
      {
        "pattern": "Ports and Adapters (Hexagonal Architecture)",
        "rationale": "Core domain defines port interfaces (e.g., CarrierGateway, OrderConfirmationSource). Adapters implement these ports for specific technologies (SFTP, REST, Kafka). This makes the core testable in isolation and allows swapping integrations without touching domain logic."
      },
      {
        "pattern": "Async Webhook Ingestion (Receive-and-Enqueue)",
        "rationale": "DHL's 500ms webhook SLA is met by immediately acknowledging receipt and enqueuing for async processing. This decouples the HTTP response time from domain processing time, preventing slow DB writes or downstream failures from violating the SLA."
      },
      {
        "pattern": "Idempotent Event Processing",
        "rationale": "At-least-once delivery means every consumer must handle duplicates. Each event carries a unique eventId, and consumers track processed IDs to skip duplicates. Critical for the SAP file poller (same file fetched twice) and DHL webhooks (retried callbacks)."
      },
      {
        "pattern": "Circuit Breaker (on DHL outbound calls)",
        "rationale": "DHL API is an external dependency with its own availability characteristics. A circuit breaker prevents cascading failures when DHL is down, allowing shipment creation to be retried from the event bus after the circuit closes."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": [
          "Order (root) — contains OrderLines, tracks lifecycle from Placed → Confirmed. Invariants: order cannot be confirmed twice, line items must match original order."
        ]
      },
      {
        "name": "Shipment & Delivery",
        "classification": "core",
        "aggregates": [
          "Shipment (root) — tracks lifecycle from Created → DeliveryAttempted → Completed/Failed. Invariants: shipment requires confirmed order, max delivery attempts, cannot complete after failure without new attempt."
        ]
      },
      {
        "name": "ERP Integration",
        "classification": "generic",
        "aggregates": [
          "SFTPFileTracker — tracks processed files to ensure idempotency. Not a true domain aggregate, more of an infrastructure concern."
        ]
      },
      {
        "name": "Carrier Integration",
        "classification": "supporting",
        "aggregates": [
          "CarrierShipmentMapping — maps internal shipmentId to carrier-specific tracking IDs and statuses. Owns the translation table between DHL status codes and domain delivery statuses."
        ]
      },
      {
        "name": "Analytics Integration",
        "classification": "generic",
        "aggregates": []
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Shipment & Delivery",
        "relationship": "Customer-Supplier — Shipment context reacts to OrderConfirmed events. Order context defines the event schema; Shipment context conforms to it."
      },
      {
        "upstream": "ERP Integration (SAP)",
        "downstream": "Order Management",
        "relationship": "Anti-Corruption Layer — SAP's XML model is translated into OrderConfirmed domain commands. SAP is upstream in terms of data flow but downstream in terms of model authority (our domain defines what 'confirmed' means)."
      },
      {
        "upstream": "Shipment & Delivery",
        "downstream": "Carrier Integration (DHL)",
        "relationship": "Open Host Service / ACL — Shipment context publishes events via a clean interface. DHL adapter translates bidirectionally: outbound domain→DHL API, inbound DHL webhook→domain events."
      },
      {
        "upstream": "Order Management + Shipment & Delivery",
        "downstream": "Analytics Integration",
        "relationship": "Published Language — All domain events follow a canonical envelope schema. Analytics adapter is a Conformist: it adapts to whatever events the domain publishes."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Async webhook processing (enqueue + return 200) instead of synchronous domain processing in the webhook handler",
      "gains": "Guarantees sub-500ms webhook response time regardless of domain processing complexity. Decouples availability of domain services from webhook SLA. Enables retry from queue if processing fails.",
      "sacrifices": "Adds eventual consistency — there is a delay between DHL's callback and the domain event being fully processed. Requires a durable queue (adds infrastructure). Slightly more complex error handling (DLQ needed).",
      "alternatives_considered": [
        "Synchronous processing in webhook handler — simpler but risks 500ms SLA violation under load or when DB is slow",
        "Batch processing webhooks on a schedule — too much latency for real-time analytics requirement"
      ]
    },
    {
      "decision": "Transactional outbox over direct event bus publication",
      "gains": "Zero event loss. No distributed transactions needed. Works with any relational DB. Well-understood pattern with proven reliability.",
      "sacrifices": "Adds latency (relay polling interval, typically 100ms-1s). Outbox table grows and needs cleanup. Relay process is another component to operate.",
      "alternatives_considered": [
        "CDC (Change Data Capture) via Debezium — more elegant but adds significant infrastructure complexity",
        "Direct Kafka production in same thread — risks event loss if Kafka is unavailable at write time",
        "Saga/2PC — too heavyweight for this use case"
      ]
    },
    {
      "decision": "Separate ACL per external system rather than a unified integration layer",
      "gains": "Each adapter evolves independently. Failure in one integration doesn't cascade. Clear ownership and testability. Can scale adapters independently.",
      "sacrifices": "More components to deploy and monitor. Some boilerplate duplication across adapters (event subscription, error handling). Higher initial setup cost.",
      "alternatives_considered": [
        "Unified ESB/integration middleware — single point of failure, becomes a monolithic bottleneck, hard to version independently",
        "Shared integration library — creates hidden coupling between adapters"
      ]
    },
    {
      "decision": "Internal event bus (Kafka or lightweight broker) rather than direct method calls between services",
      "gains": "Temporal decoupling — producers and consumers don't need to be online simultaneously. Easy to add new consumers (e.g., a 4th external system) without modifying producers. Natural audit log.",
      "sacrifices": "Eventual consistency throughout. Harder to debug end-to-end flows. Requires idempotent consumers. Message ordering must be managed (partition by aggregateId).",
      "alternatives_considered": [
        "Synchronous service calls — simpler but creates tight coupling and cascading failures",
        "Shared database — eliminates messaging but creates a distributed monolith"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Carrier integration",
      "evolution_path": "Adding a new carrier (UPS, FedEx) requires only implementing a new adapter behind the CarrierGateway port. No core domain changes. The DHL adapter serves as a template."
    },
    {
      "area": "ERP system swap",
      "evolution_path": "Replacing SAP with another ERP requires only a new adapter that produces OrderConfirmed commands. Could switch from SFTP/XML to API/JSON without touching the order domain."
    },
    {
      "area": "Analytics platform",
      "evolution_path": "Switching from Kafka to another streaming platform (Kinesis, Pulsar) or adding a second analytics consumer only affects the Analytics Adapter. The internal event bus remains unchanged."
    },
    {
      "area": "New domain events",
      "evolution_path": "Adding events (e.g., OrderCancelled, ShipmentRerouted) follows the same pattern: domain service publishes to outbox → bus → adapters that care subscribe. No architectural changes needed."
    },
    {
      "area": "Webhook ingress scaling",
      "evolution_path": "The webhook gateway can be scaled horizontally behind a load balancer independently of domain services, since it only enqueues."
    }
  ],

  "rigidity_points": [
    {
      "area": "Domain event schema (canonical envelope)",
      "reason": "All adapters depend on the event envelope format { eventType, eventId, timestamp, aggregateId, payload }. Changing this schema requires coordinated updates across all consumers. This is intentional — the canonical model is the stable contract that enables loose coupling everywhere else."
    },
    {
      "area": "At-least-once delivery semantic",
      "reason": "The entire architecture assumes at-least-once delivery and idempotent consumers. Switching to exactly-once would require fundamental changes to the outbox, bus, and all consumers. This is a deliberate and appropriate constraint."
    },
    {
      "area": "Aggregate boundaries (Order and Shipment as separate aggregates)",
      "reason": "These are the core consistency boundaries. Merging them would create a god-aggregate with too many invariants. Splitting them further would make cross-concern transactions harder. These boundaries should be stable."
    }
  ],

  "risks": [
    {
      "risk": "SAP SFTP polling misses files or processes them out of order if file timestamps are unreliable",
      "severity": "high",
      "mitigation": "Track processed files by name AND content hash in SFTPFileTracker. Use lexicographic ordering as tiebreaker. Implement a reconciliation job that periodically compares SAP order IDs against confirmed orders to catch gaps."
    },
    {
      "risk": "DHL webhook replay/duplication causes duplicate domain events (e.g., double DeliveryCompleted)",
      "severity": "high",
      "mitigation": "DHL Adapter must be idempotent: deduplicate by DHL event ID before translating to domain events. Shipment aggregate enforces state machine invariants (cannot transition Completed → Completed)."
    },
    {
      "risk": "Analytics Kafka producer falls behind during traffic spikes, causing backpressure on the internal event bus",
      "severity": "medium",
      "mitigation": "Analytics adapter should have its own consumer group with independent offset tracking. Use buffering and batch production. If Kafka is slow, it should not block other event bus consumers. Consider a dedicated outbox reader for analytics to fully decouple."
    },
    {
      "risk": "Webhook gateway queue grows unboundedly if domain processing is down",
      "severity": "medium",
      "mitigation": "Set queue depth alerts. Implement dead-letter queue with monitoring. DHL webhooks have built-in retry — if we return 5xx, DHL will retry, so we can also use backpressure by temporarily rejecting webhooks (return 503) if the queue exceeds a threshold."
    },
    {
      "risk": "Event ordering: analytics sees DeliveryCompleted before ShipmentCreated if events are processed out of order",
      "severity": "medium",
      "mitigation": "Partition internal event bus by orderId/shipmentId to guarantee ordering within an aggregate. Analytics consumers must handle late-arriving events gracefully (event timestamp is authoritative, not arrival order)."
    },
    {
      "risk": "Outbox relay becomes a bottleneck under high event volume",
      "severity": "low",
      "mitigation": "Relay can be horizontally scaled by partitioning the outbox table (e.g., by aggregate ID modulo). Consider switching to CDC (Debezium) if polling latency becomes unacceptable at scale."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Implement in phases: Phase 1 — Core domain (Order + Shipment aggregates) with internal event bus and transactional outbox. Phase 2 — SAP adapter (read-only integration, lowest risk). Phase 3 — DHL adapter (bidirectional, higher complexity, needs webhook gateway). Phase 4 — Analytics Kafka adapter (read-only consumer of all events). Each phase is independently deployable and testable.",
    "files_to_create_or_modify": [
      "src/domain/order/Order.ts — Order aggregate root",
      "src/domain/order/events.ts — OrderPlaced, OrderConfirmed event definitions",
      "src/domain/shipment/Shipment.ts — Shipment aggregate root with state machine",
      "src/domain/shipment/events.ts — ShipmentCreated, DeliveryAttempted, DeliveryCompleted, DeliveryFailed",
      "src/domain/events/DomainEvent.ts — Canonical event envelope interface",
      "src/infrastructure/outbox/OutboxTable.ts — Outbox schema and repository",
      "src/infrastructure/outbox/OutboxRelay.ts — Polls outbox, publishes to event bus",
      "src/adapters/sap/SapSftpPoller.ts — SFTP polling, XML parsing, file tracking",
      "src/adapters/sap/SapXmlTranslator.ts — XML → OrderConfirmed translation",
      "src/adapters/dhl/DhlApiClient.ts — Outbound REST client with circuit breaker",
      "src/adapters/dhl/DhlWebhookHandler.ts — Inbound webhook → queue enqueue",
      "src/adapters/dhl/DhlEventTranslator.ts — DHL status → domain event translation",
      "src/adapters/analytics/AnalyticsKafkaProducer.ts — Domain event → Kafka analytics schema",
      "src/ports/CarrierGateway.ts — Port interface for carrier operations",
      "src/ports/OrderConfirmationSource.ts — Port interface for ERP confirmations"
    ],
    "patterns_to_follow": "Hexagonal architecture with ports (interfaces in domain layer) and adapters (implementations in adapter layer). All external I/O behind interfaces. Domain events as the primary integration mechanism. State machine pattern for Shipment lifecycle. Repository pattern for aggregate persistence.",
    "pitfalls_to_avoid": [
      "DO NOT let SAP XML types leak into domain layer — translate at the adapter boundary",
      "DO NOT process DHL webhooks synchronously — always enqueue first, process second",
      "DO NOT share database tables between bounded contexts — each context owns its storage",
      "DO NOT use the analytics Kafka topic as the internal event bus — keep internal and external buses separate",
      "DO NOT assume DHL webhook order matches chronological order — use event timestamps, not arrival order",
      "DO NOT skip idempotency keys on any consumer — at-least-once means duplicates WILL happen",
      "DO NOT couple the outbox relay to a specific consumer — it should publish to the bus, not directly to adapters"
    ]
  },

